// // This module implements a 8-bit register that holds the value of the 'exponent' input. On the negative edge of the 'clk', if the 'clear' signal is deasserted, the register resets to zero. If the 'load' signal is deasserted, the register captures and stores the value from the 'exponent' input.
module top_module(
    input [7:0]exponent,
    input clk, clear, load,
    output reg [7:0]saved_exp
    );always @(posedge clk)
        if(clear)
            saved_exp <= 8'b0;
        else if(load)
            saved_exp <= exponent;

endmodule
